```rust
use tokio::task::JoinSet;
use std::time::Duration;

#[derive(Debug)]
struct JobResult {
    id: usize,
    value: String,
}

async fn simulate_job(id: usize) -> JobResult {
    // Simulate variable-latency work
    let delay = Duration::from_millis((10 - id as u64 % 10) * 20);
    tokio::time::sleep(delay).await;
    JobResult {
        id,
        value: format!("result-{id}"),
    }
}

#[tokio::main]
async fn main() {
    let mut set = JoinSet::new();

    for id in 0..10 {
        set.spawn(simulate_job(id));
    }

    let mut results = Vec::new();
    while let Some(res) = set.join_next().await {
        match res {
            Ok(job_result) => results.push(job_result),
            Err(e) => eprintln!("Task panicked: {e}"),
        }
    }

    // Results arrive in completion order, not spawn order
    println!("Completed {} jobs", results.len());
    for r in &results {
        println!("  {:?}", r);
    }
}
```

**Key points:**
- `JoinSet` owns the spawned tasks and drives them to completion via `join_next()`.
- `join_next()` returns `None` when the set is empty — no busy-waiting.
- Each `join_next()` call returns the *first completed* task, giving true completion-order results.
- Panics in tasks surface as `Err(JoinError)`, not as crashes in the caller.
- Unlike `join_all`, this lets you process results incrementally as they finish.

```rust
use tokio::sync::mpsc;
use tokio::time::{Duration, sleep};

#[derive(Debug)]
struct WorkItem(u64);

async fn producer(tx: mpsc::Sender<WorkItem>, id: u64, count: u64) {
    for i in 0..count {
        let item = WorkItem(id * 1000 + i);
        if tx.send(item).await.is_err() {
            // Receiver dropped — stop producing
            break;
        }
        sleep(Duration::from_millis(10)).await;
    }
    // tx is dropped here, signalling this producer is done
}

async fn batching_consumer(mut rx: mpsc::Receiver<WorkItem>) {
    let mut batch: Vec<WorkItem> = Vec::with_capacity(10);

    loop {
        // Try to fill a batch of 10
        match rx.recv().await {
            None => {
                // All senders dropped — flush remaining items
                if !batch.is_empty() {
                    process_batch(&batch);
                }
                break;
            }
            Some(item) => {
                batch.push(item);
                if batch.len() >= 10 {
                    process_batch(&batch);
                    batch.clear();
                }
            }
        }
    }
}

fn process_batch(batch: &[WorkItem]) {
    println!("Processing batch of {}: {:?}", batch.len(), batch);
}

#[tokio::main]
async fn main() {
    // Buffer of 32 — back-pressures producers if consumer is slow
    let (tx, rx) = mpsc::channel::<WorkItem>(32);

    let consumer = tokio::spawn(batching_consumer(rx));

    let mut producers = Vec::new();
    for id in 0..4 {
        producers.push(tokio::spawn(producer(tx.clone(), id, 8)));
    }
    // Drop the original tx so the last clone dropping closes the channel
    drop(tx);

    for p in producers {
        p.await.unwrap();
    }
    consumer.await.unwrap();
}
```

**Design notes:**
- The channel is closed when **all** `Sender` clones are dropped. Dropping the original `tx` after cloning for producers is essential.
- A bounded channel (`mpsc::channel(32)`) applies back-pressure: `send().await` blocks when the buffer is full, preventing unbounded memory growth.
- `recv()` returning `None` is the idiomatic EOF signal — no extra sentinel value needed.

```rust
use tokio::net::{TcpListener, TcpStream};
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::time::{timeout, Duration};
use std::io;

async fn handle_connection(mut stream: TcpStream, addr: std::net::SocketAddr) {
    println!("New connection from {addr}");
    let mut buf = vec![0u8; 4096];

    loop {
        // Each read must complete within 30 seconds
        let n = match timeout(
            Duration::from_secs(30),
            stream.read(&mut buf),
        ).await {
            Ok(Ok(0)) => {
                println!("{addr}: connection closed by peer");
                break;
            }
            Ok(Ok(n)) => n,
            Ok(Err(e)) => {
                eprintln!("{addr}: read error: {e}");
                break;
            }
            Err(_) => {
                eprintln!("{addr}: read timeout — dropping connection");
                // stream dropped here closes the TCP connection
                break;
            }
        };

        // Echo back
        if let Err(e) = stream.write_all(&buf[..n]).await {
            eprintln!("{addr}: write error: {e}");
            break;
        }
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    println!("Echo server listening on port 8080");

    loop {
        let (stream, addr) = listener.accept().await?;
        // Each connection runs independently — one slow client can't block others
        tokio::spawn(handle_connection(stream, addr));
    }
}
```

**Concurrency model:**
- `tokio::spawn` gives each connection its own task on the Tokio thread pool.
- The main loop never blocks — `accept()` yields to the runtime between connections.
- Dropping `TcpStream` sends a TCP FIN, cleanly terminating the connection.
- `timeout` wraps a single future; the stream is not dropped until the `break`.

```rust
use tokio::sync::{mpsc, oneshot};

// Command enum carries the request payload and a oneshot sender for the reply
#[derive(Debug)]
enum Command {
    Get { key: String, respond_to: oneshot::Sender<Option<String>> },
    Set { key: String, value: String, respond_to: oneshot::Sender<()> },
}

// Actor: owns state and processes commands sequentially
async fn store_actor(mut rx: mpsc::Receiver<Command>) {
    let mut map = std::collections::HashMap::<String, String>::new();

    while let Some(cmd) = rx.recv().await {
        match cmd {
            Command::Get { key, respond_to } => {
                let value = map.get(&key).cloned();
                // Ignore send error — caller may have timed out
                let _ = respond_to.send(value);
            }
            Command::Set { key, value, respond_to } => {
                map.insert(key, value);
                let _ = respond_to.send(());
            }
        }
    }
}

// Handle is a cheap clone for sending commands
#[derive(Clone)]
struct StoreHandle {
    tx: mpsc::Sender<Command>,
}

impl StoreHandle {
    fn new() -> Self {
        let (tx, rx) = mpsc::channel(32);
        tokio::spawn(store_actor(rx));
        Self { tx }
    }

    async fn get(&self, key: impl Into<String>) -> Option<String> {
        let (respond_to, rx) = oneshot::channel();
        self.tx.send(Command::Get { key: key.into(), respond_to }).await.unwrap();
        rx.await.unwrap()
    }

    async fn set(&self, key: impl Into<String>, value: impl Into<String>) {
        let (respond_to, rx) = oneshot::channel();
        self.tx.send(Command::Set {
            key: key.into(),
            value: value.into(),
            respond_to,
        }).await.unwrap();
        rx.await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let store = StoreHandle::new();

    store.set("name", "Hive").await;
    let name = store.get("name").await;
    println!("{:?}", name); // Some("Hive")

    // Multiple callers can use the handle concurrently
    let s2 = store.clone();
    let task = tokio::spawn(async move { s2.get("name").await });
    println!("{:?}", task.await.unwrap());
}
```

This is the **actor pattern** — the central Rust idiom for safe shared mutable state in async code. The actor serialises all access, eliminating the need for `Arc<Mutex<T>>` around the map.

```rust
use tokio::sync::broadcast;
use tokio::time::{Duration, sleep};

#[derive(Clone, Debug)]
struct Quote {
    symbol: String,
    price: f64,
}

async fn price_publisher(tx: broadcast::Sender<Quote>) {
    let prices = [100.0, 101.5, 99.8, 102.3, 101.0, 103.7];
    for price in prices {
        let quote = Quote { symbol: "HIVE".to_string(), price };
        println!("Publishing: {:.2}", price);
        // send() fails only if there are zero receivers
        if tx.send(quote).is_err() {
            break;
        }
        sleep(Duration::from_millis(100)).await;
    }
}

async fn moving_average_subscriber(mut rx: broadcast::Receiver<Quote>, id: u64) {
    let mut sum = 0.0;
    let mut count = 0u64;

    loop {
        match rx.recv().await {
            Ok(quote) => {
                sum += quote.price;
                count += 1;
                let avg = sum / count as f64;
                println!("Subscriber {id}: received {:.2}, avg = {avg:.4}", quote.price);
            }
            Err(broadcast::error::RecvError::Lagged(n)) => {
                // This subscriber missed n messages — handle or reset
                eprintln!("Subscriber {id} lagged by {n} messages");
            }
            Err(broadcast::error::RecvError::Closed) => {
                println!("Subscriber {id}: channel closed, final avg = {:.4}", sum / count as f64);
                break;
            }
        }
    }
}

#[tokio::main]
async fn main() {
    // Capacity 16 — subscribers that fall >16 messages behind get Lagged error
    let (tx, _) = broadcast::channel::<Quote>(16);

    // Spawn 3 independent subscribers
    let mut tasks = Vec::new();
    for id in 0..3 {
        let rx = tx.subscribe();
        tasks.push(tokio::spawn(moving_average_subscriber(rx, id)));
    }

    price_publisher(tx).await;

    for t in tasks {
        t.await.unwrap();
    }
}
```

**broadcast vs mpsc:** Each broadcast receiver gets its own copy of every message. The `Lagged` error is critical — slow subscribers don't block fast ones, they simply skip messages and are told how many they missed.

```rust
use tokio::net::UdpSocket;
use std::io;

/// Simple binary protocol:
/// Request:  [u8 op] [u32 a] [u32 b]  (9 bytes, big-endian)
/// Response: [u32 result]              (4 bytes, big-endian)
/// ops: 0=add, 1=sub, 2=mul

fn parse_request(buf: &[u8]) -> Option<(u8, u32, u32)> {
    if buf.len() < 9 { return None; }
    let op = buf[0];
    let a = u32::from_be_bytes(buf[1..5].try_into().ok()?);
    let b = u32::from_be_bytes(buf[5..9].try_into().ok()?);
    Some((op, a, b))
}

fn compute(op: u8, a: u32, b: u32) -> Option<u32> {
    match op {
        0 => a.checked_add(b),
        1 => a.checked_sub(b),
        2 => a.checked_mul(b),
        _ => None,
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    // UdpSocket is wrapped by Tokio for non-blocking operation
    let socket = UdpSocket::bind("127.0.0.1:9000").await?;
    println!("UDP calc server on port 9000");

    let mut buf = [0u8; 1024];

    loop {
        // recv_from yields (bytes_read, sender_addr)
        let (n, peer) = socket.recv_from(&mut buf).await?;

        match parse_request(&buf[..n]) {
            Some((op, a, b)) => match compute(op, a, b) {
                Some(result) => {
                    let response = result.to_be_bytes();
                    socket.send_to(&response, peer).await?;
                }
                None => {
                    eprintln!("Overflow or unknown op from {peer}");
                }
            },
            None => {
                eprintln!("Malformed datagram from {peer} ({n} bytes)");
            }
        }
    }
}

// Client example (for testing):
// async fn send_request(socket: &UdpSocket, op: u8, a: u32, b: u32) -> u32 {
//     let mut req = [0u8; 9];
//     req[0] = op;
