**UDP notes:** Unlike TCP, UDP has no connection — you handle each datagram independently. A single `UdpSocket` can serve many clients. For high-throughput servers, wrap the socket in `Arc` and spawn multiple reader tasks.

```rust
use tokio::sync::{mpsc, Semaphore};
use tokio::time::{interval, Duration};
use std::sync::Arc;

/// Token-bucket rate limiter: allows `rate` permits per second.
/// Shared across any number of async tasks via Arc.
struct RateLimiter {
    semaphore: Arc<Semaphore>,
}

impl RateLimiter {
    fn new(rate: usize) -> Self {
        let semaphore = Arc::new(Semaphore::new(0));
        let sem_clone = semaphore.clone();

        // Background task: adds `rate` permits every second
        tokio::spawn(async move {
            let mut ticker = interval(Duration::from_secs(1));
            loop {
                ticker.tick().await;
                // add_permits won't exceed usize::MAX, safe to call repeatedly
                sem_clone.add_permits(rate);
            }
        });

        Self { semaphore }
    }

    async fn acquire(&self) {
        // Blocks until a permit is available
        self.semaphore
            .acquire()
            .await
            .expect("rate limiter semaphore closed")
            .forget(); // release ownership — permits are re-added by the ticker
    }
}

async fn producer(id: u64, limiter: Arc<RateLimiter>, tx: mpsc::Sender<String>) {
    for i in 0..5 {
        limiter.acquire().await;
        let msg = format!("producer-{id} item-{i}");
        println!("[{:.3?}] {msg}", std::time::Instant::now());
        tx.send(msg).await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let limiter = Arc::new(RateLimiter::new(3)); // 3 ops/sec globally
    let (tx, mut rx) = mpsc::channel(100);

    for id in 0..4 {
        tokio::spawn(producer(id, limiter.clone(), tx.clone()));
    }
    drop(tx);

    while let Some(msg) = rx.recv().await {
        let _ = msg;
    }
    println!("All done");
}
```

**Why `forget()`?** `SemaphorePermit` is an RAII guard that returns the permit on drop. We call `forget()` to suppress that — permits are budget tokens re-added by the ticker, not individual resources to return.

```rust
use tokio::sync::{Mutex, Semaphore};
use std::sync::Arc;
use std::collections::VecDeque;

/// A mock database connection
struct Connection {
    id: u64,
}

impl Connection {
    async fn new(id: u64) -> Self {
        // Simulate connection setup latency
        tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;
        println!("Created connection {id}");
        Self { id }
    }

    async fn query(&self, sql: &str) -> String {
        format!("[conn {}] result of `{}`", self.id, sql)
    }
}

struct Pool {
    connections: Mutex<VecDeque<Connection>>,
    semaphore: Semaphore,
    max_size: u64,
    next_id: Mutex<u64>,
}

impl Pool {
    fn new(max_size: u64) -> Arc<Self> {
        Arc::new(Self {
            connections: Mutex::new(VecDeque::new()),
            semaphore: Semaphore::new(max_size as usize),
            max_size,
            next_id: Mutex::new(0),
        })
    }

    async fn get(&self) -> PooledConn<'_> {
        // Acquire permit first — blocks if pool is exhausted
        let permit = self.semaphore.acquire().await.unwrap();

        let conn = {
            let mut queue = self.connections.lock().await;
            queue.pop_front()
        };

        let conn = match conn {
            Some(c) => c,
            None => {
                let mut id = self.next_id.lock().await;
                let c = Connection::new(*id).await;
                *id += 1;
                c
            }
        };

        PooledConn {
            conn: Some(conn),
            pool: self,
            _permit: permit,
        }
    }

    fn recycle(&self, conn: Connection) {
        if let Ok(mut queue) = self.connections.try_lock() {
            queue.push_back(conn);
        }
        // If lock fails, connection is simply dropped (acceptable)
    }
}

/// RAII guard that returns the connection when dropped
struct PooledConn<'a> {
    conn: Option<Connection>,
    pool: &'a Pool,
    _permit: tokio::sync::SemaphorePermit<'a>,
}

impl<'a> PooledConn<'a> {
    async fn query(&self, sql: &str) -> String {
        self.conn.as_ref().unwrap().query(sql).await
    }
}

impl<'a> Drop for PooledConn<'a> {
    fn drop(&mut self) {
        if let Some(conn) = self.conn.take() {
            self.pool.recycle(conn);
        }
        // _permit is dropped here, releasing the semaphore slot
    }
}

#[tokio::main]
async fn main() {
    let pool = Pool::new(3);

    let mut tasks = Vec::new();
    for i in 0..8 {
        let p = pool.clone();
        tasks.push(tokio::spawn(async move {
            let conn = p.get().await;
            let result = conn.query(&format!("SELECT {i}")).await;
            println!("{result}");
        }));
    }
    for t in tasks { t.await.unwrap(); }
}
```

```rust
use anyhow::{Context, Result, bail};
use std::fs;
use std::path::Path;

#[derive(Debug)]
struct Config {
    db_url: String,
    max_connections: u32,
}

fn parse_max_connections(value: &str) -> Result<u32> {
    value
        .parse::<u32>()
        .with_context(|| format!("max_connections must be a positive integer, got `{value}`"))
}

fn parse_config(content: &str) -> Result<Config> {
    let mut db_url = None;
    let mut max_connections = None;

    for (line_no, line) in content.lines().enumerate() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') { continue; }

        let (key, val) = line.split_once('=')
            .with_context(|| format!("line {}: expected `key=value`, got `{line}`", line_no + 1))?;

        match key.trim() {
            "db_url" => db_url = Some(val.trim().to_string()),
            "max_connections" => {
                max_connections = Some(
                    parse_max_connections(val.trim())
                        .context("while parsing max_connections")?  // static context
                );
            }
            other => bail!("unknown config key: `{other}` at line {}", line_no + 1),
        }
    }

    Ok(Config {
        db_url: db_url.context("missing required key `db_url`")?,
        max_connections: max_connections.unwrap_or(10),
    })
}

fn load_config(path: &Path) -> Result<Config> {
    let content = fs::read_to_string(path)
        .with_context(|| format!("failed to read config file `{}`", path.display()))?;
    parse_config(&content)
        .context("failed to parse config")
}

fn main() -> Result<()> {
    let config = load_config(Path::new("app.toml"))?;
    println!("{config:?}");
    Ok(())
}
```

**Error chain output** (with `{:?}` or `RUST_BACKTRACE=1`):
```
failed to parse config

Caused by:
    0: while parsing max_connections
    1: max_connections must be a positive integer, got `abc`
    2: invalid digit found in string
```

**Rules:**
- `.context("static string")` — always evaluated, cheapest.
- `.with_context(|| ...)` — closure only runs on error, use for allocating messages.
- `anyhow` is for *applications*; libraries should use typed errors (`thiserror`).

```rust
/// A trait for computing statistics over a sequence of values.
/// The associated type lets each implementor specify its output type.
trait Statistics {
    type Output;
    fn mean(&self) -> Option<Self::Output>;
    fn variance(&self) -> Option<Self::Output>;
}

/// A newtype wrapper so we can impl Statistics for slices without
/// violating the orphan rule.
struct Samples<'a>(&'a [f64]);

impl<'a> Statistics for Samples<'a> {
    type Output = f64;

    fn mean(&self) -> Option<f64> {
        if self.0.is_empty() { return None; }
        Some(self.0.iter().sum::<f64>() / self.0.len() as f64)
    }

    fn variance(&self) -> Option<f64> {
        let mean = self.mean()?;
        let var = self.0.iter()
            .map(|x| (x - mean).powi(2))
            .sum::<f64>() / self.0.len() as f64;
        Some(var)
    }
}

/// Blanket impl: any type that implements Statistics also gets std_dev for free.
trait StdDev: Statistics<Output = f64> {
    fn std_dev(&self) -> Option<f64> {
        self.variance().map(f64::sqrt)
    }
}

// The blanket impl — applies to all Statistics<Output=f64> implementors
impl<T: Statistics<Output = f64>> StdDev for T {}

// --- A second implementor with a different Output type ---
struct RunLengths(Vec<usize>);

impl Statistics for RunLengths {
    type Output = f64; // coerce to f64 for consistency

    fn mean(&self) -> Option<f64> {
        if self.0.is_empty() { return None; }
        Some(self.0.iter().sum::<usize>() as f64 / self.0.len() as f64)
    }

    fn variance(&self) -> Option<f64> {
        let mean = self.mean()?;
        let var = self.0.iter()
            .map(|&x| (x as f64 - mean).powi(2))
            .sum::<f64>() / self.0.len() as f64;
        Some(var)
    }
}
// RunLengths also gets StdDev for free via the blanket impl

fn main() {
    let data = Samples(&[2.0, 4.0, 4.0, 4.0, 5.0, 5.0, 7.0, 9.0]);
    println!("mean     = {:?}", data.mean());
    println!("variance = {:?}", data.variance());
    println!("std_dev  = {:?}", data.std_dev());

    let runs = RunLengths(vec![3, 5, 2, 8, 1]);
    println!("std_dev  = {:?}", runs.std_dev());
}
```

**Key concepts:**
- Associated types (`type Output`) let the caller use `T::Output` without extra type parameters, keeping bounds clean.
- Blanket impls (`impl<T: Trait> OtherTrait for T`) extend behaviour across an entire family of types.
- The orphan rule prevents implementing a foreign trait on a foreign type — the `Samples` newtype sidesteps this.

```rust
use std::fmt;

trait Render: fmt::Debug {
    fn render(&self) -> String;
    fn priority(&self) -> u8 { 0 } // default impl
}

#[derive(Debug)] struct TextWidget(String);
#[derive(Debug)] struct ImageWidget { url: String, width: u32 }

impl Render for TextWidget {
    fn render(&self) -> String { format!("<p>{}</p>", self.0) }
}

impl Render for ImageWidget {
    fn render(&self) -> String {
        format!("<img src='{}' width='{}'>", self.url, self.width)
    }
    fn priority(&self) -> u8 { 10 }
}

// ---- GENERIC VERSION ----
// Monomorphised: the compiler emits a separate function for each T.
// Zero overhead at runtime, but T must be known at compile time.
fn render_generic<T: Render>(widget: &T) -> String {
    widget.render()
}

// ---- TRAIT OBJECT VERSION ----
// One function, one compiled body. T is erased. Virtual dispatch via vtable.
// Allows heterogeneous collections.
fn render_dyn(widget: &dyn Render) -> String {
    widget.render()
}

// Only possible with dyn Trait — generics can't hold different concrete types.
fn render_all(widgets: &[Box<dyn Render>]) -> Vec<String> {
    widgets.iter().map(|w| w.render()).collect()
}

// impl Trait in argument position = sugar for a generic
fn log_widget(widget: &impl Render) {
    println!("[priority {}] {:?}", widget.priority(), widget);
}

// impl Trait in return position = one concrete type, hidden from caller
// (NOT the same as `dyn Trait` — the type is still monomorphic)
fn make_default_widget() -> impl Render {
    TextWidget("Hello".to_string())
}

fn main() {
    let text = TextWidget("Hello World".to_string());
    let img = ImageWidget { url: "logo.png".to_string(), width: 100 };

    // Generic — zero-cost
    println!("{}", render_generic(&text));
    println!("{}", render_generic(&img));

    // Trait object — virtual dispatch
    let widgets: Vec<Box<dyn Render>> = vec![
        Box::new(TextWidget("One".to_string())),
        Box::new(ImageWidget { url: "a.png".to_string(), width: 50 }),
    ];
    for r in render_all(&widgets) {
        println!("{r}");
    }

    log_widget(&text);
    let w = make_default_widget();
    println!("{}", w.render());
}
```

| | `T: Trait` / `impl Trait` | `dyn Trait` |
|---|---|---|
| Dispatch | Static (inlined) | Virtual (vtable ptr) |
| Code size | Bloat (one copy per T) | One copy |
| Heterogeneous collections | No | Yes |
| Object safety required | No | Yes |
| Suitable for | Hot paths, closures | Plugin systems, mixed types |

