// Suppose we want to add a method to Vec<f64> from an external crate.
// The orphan rule forbids: impl ExternalTrait for Vec<f64> if both are foreign.
// Solution 1: Newtype wrapper

use std::fmt;

/// Newtype wraps the foreign type
pub struct Stats(pub Vec<f64>);

impl Stats {
    pub fn mean(&self) -> Option<f64> {
        if self.0.is_empty() { return None; }
        Some(self.0.iter().sum::<f64>() / self.0.len() as f64)
    }

    pub fn median(&self) -> Option<f64> {
        if self.0.is_empty() { return None; }
        let mut sorted = self.0.clone();
        sorted.sort_by(f64::total_cmp);
        let mid = sorted.len() / 2;
        Some(if sorted.len() % 2 == 0 {
            (sorted[mid - 1] + sorted[mid]) / 2.0
        } else {
            sorted[mid]
        })
    }
}

// We CAN implement standard traits on our newtype
impl fmt::Display for Stats {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Stats([{} items])", self.0.len())
    }
}

// Allow dereferencing to the inner Vec for convenience
impl std::ops::Deref for Stats {
    type Target = Vec<f64>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

// ----- Sealed Trait Pattern -----
// Useful when you want to constrain who can implement your public trait.

mod private {
    // This trait is in a private module — external code can't name it
    pub trait Sealed {}
}

/// Public trait, but only types that impl the private Sealed trait can use it.
/// External crates cannot implement SealedOps because they can't name `private::Sealed`.
pub trait SealedOps: private::Sealed {
    fn double(&self) -> Self;
}

// We control which types get the capability
impl private::Sealed for i32 {}
impl SealedOps for i32 {
    fn double(&self) -> Self { self * 2 }
}

impl private::Sealed for f64 {}
impl SealedOps for f64 {
    fn double(&self) -> Self { self * 2.0 }
}

fn main() {
    let data = Stats(vec![1.0, 3.0, 5.0, 7.0, 9.0]);
    println!("mean   = {:?}", data.mean());
    println!("median = {:?}", data.median());
    println!("{data}");

    println!("{}", 21i32.double());
    println!("{}", 3.14f64.double());
}
```

**Newtype vs Sealed:**
- **Newtype**: Use when wrapping a foreign type to add methods or implement foreign traits.
- **Sealed**: Use when you own a public trait but want to prevent external types from implementing it (stable API guarantee pattern used by many std and tokio APIs).

```rust
use std::any::{Any, TypeId};
use std::collections::HashMap;

type BoxedHandler = Box<dyn Fn(&dyn Any) + Send + Sync>;

#[derive(Default)]
struct EventBus {
    handlers: HashMap<TypeId, Vec<BoxedHandler>>,
}

impl EventBus {
    pub fn subscribe<E: Any + Send + Sync>(
        &mut self,
        handler: impl Fn(&E) + Send + Sync + 'static,
    ) {
        let type_id = TypeId::of::<E>();
        // Wrap the typed handler in a type-erased closure
        let erased: BoxedHandler = Box::new(move |any_ref: &dyn Any| {
            if let Some(event) = any_ref.downcast_ref::<E>() {
                handler(event);
            }
        });
        self.handlers.entry(type_id).or_default().push(erased);
    }

    pub fn publish<E: Any + Send + Sync>(&self, event: E) {
        let type_id = TypeId::of::<E>();
        if let Some(handlers) = self.handlers.get(&type_id) {
            for handler in handlers {
                handler(&event);
            }
        }
    }
}

// --- Events ---
#[derive(Debug)] struct UserCreated { name: String }
#[derive(Debug)] struct OrderPlaced { amount: f64 }

fn main() {
    let mut bus = EventBus::default();

    bus.subscribe(|e: &UserCreated| {
        println!("Handler 1: new user `{}`", e.name);
    });
    bus.subscribe(|e: &UserCreated| {
        println!("Handler 2: send welcome email to `{}`", e.name);
    });
    bus.subscribe(|e: &OrderPlaced| {
        println!("Order handler: ${:.2} placed", e.amount);
    });

    bus.publish(UserCreated { name: "Alice".to_string() });
    bus.publish(OrderPlaced { amount: 49.99 });
    // Publishing an un-subscribed event is a no-op
    bus.publish(42u64);
}
```

**How it works:**
- `TypeId::of::<E>()` provides a runtime identity for each event type — the key to the dispatch table.
- `downcast_ref::<E>()` converts `&dyn Any` back to the concrete type safely.
- The outer closure is type-erased (`Box<dyn Fn(&dyn Any)>`), but the inner call is type-checked.
- Extending to async handlers requires changing `BoxedHandler` to return a `Pin<Box<dyn Future>>`.

