use std::pin::Pin;
use std::marker::PhantomPinned;

/// A struct that holds a String and a pointer into it.
/// This is inherently self-referential: `slice` points into `data`.
struct SelfRef {
    data: String,
    // Raw pointer into data — valid ONLY if SelfRef never moves.
    slice: *const str,
    // Opting out of Unpin makes it impossible to get &mut SelfRef
    // from Pin<&mut SelfRef>, preventing safe movement.
    _pin: PhantomPinned,
}

impl SelfRef {
    /// Must be constructed in a pinned context.
    /// Returns a Pin to heap-allocated SelfRef.
    fn new(text: String) -> Pin<Box<Self>> {
        // Initially set slice to a dangling pointer — we'll fix it after pinning
        let mut boxed = Box::pin(SelfRef {
            data: text,
            slice: std::ptr::null(),
            _pin: PhantomPinned,
        });

        // SAFETY: We only set the raw pointer; we don't move the struct.
        // After this point, boxed must never be moved.
        unsafe {
            let self_ptr: *const str = &*boxed.data;
            let mut_ref = Pin::as_mut(&mut boxed);
            // get_unchecked_mut is the only way to get &mut when PhantomPinned
            Pin::get_unchecked_mut(mut_ref).slice = self_ptr;
        }

        boxed
    }

    fn data(self: Pin<&Self>) -> &str {
        &self.data
    }

    fn slice(self: Pin<&Self>) -> &str {
        // SAFETY: slice was set to point into data, and the struct is pinned
        // so data has not moved since initialization.
        unsafe { &*self.slice }
    }
}

fn main() {
    let s = SelfRef::new("Hello, Pin!".to_string());
    let s = s.as_ref();
    println!("data  = {}", s.data());
    println!("slice = {}", s.slice());
}
```

