    data: String,
    slice: &str,  // ERROR: missing lifetime — whose lifetime?
}

// Attempt 2: add lifetime
struct Broken2<'a> {
    data: String,
    slice: &'a str,  // ERROR: 'a must outlive Broken2, but slice borrows from data
}                     // Rust's borrow checker rejects this circular dependency.

// Attempt 3: unsafe raw pointer WITHOUT Pin
struct Broken3 {
    data: String,
    slice: *const str, // Compiles, but moving the struct invalidates the pointer!
}
let b = Broken3 { data: String::from("hi"), slice: std::ptr::null() };
let b2 = b; // Moved! b2.slice still points to old stack location — UB.
```

`Pin<P>` guarantees that the pointee will never be moved in memory, making self-referential structs sound.

