use std::cell::{Cell, RefCell};
use std::sync::{Arc, Mutex};
use std::thread;

// ---- Cell<T>: single-threaded, Copy types only, zero overhead ----
#[derive(Default)]
struct Counters {
    hits: Cell<u64>,    // Interior mutability without &mut self
    misses: Cell<u64>,
}

impl Counters {
    fn record_hit(&self) {   // &self, not &mut self
        self.hits.set(self.hits.get() + 1);
    }
    fn record_miss(&self) {
        self.misses.set(self.misses.get() + 1);
    }
    fn ratio(&self) -> f64 {
        let h = self.hits.get() as f64;
        h / (h + self.misses.get() as f64)
    }
}

// ---- RefCell<T>: single-threaded, dynamic borrow checking, any T ----
struct Graph {
    edges: RefCell<Vec<(usize, usize)>>,
}

impl Graph {
    fn add_edge(&self, a: usize, b: usize) {
        // borrow_mut() panics at runtime if already borrowed
        self.edges.borrow_mut().push((a, b));
    }
    fn degree(&self, node: usize) -> usize {
        self.edges.borrow()  // Ref<Vec<...>>, releases on drop
            .iter()
            .filter(|&&(a, b)| a == node || b == node)
            .count()
    }
}

// ---- Mutex<T>: multi-threaded, blocking, any T ----
fn concurrent_counter() {
    let counter = Arc::new(Mutex::new(0u64));
    let mut handles = Vec::new();

    for _ in 0..8 {
        let c = counter.clone();
        handles.push(thread::spawn(move || {
            let mut guard = c.lock().unwrap();
            *guard += 1;
            // MutexGuard drops here, releasing the lock
        }));
    }
    for h in handles { h.join().unwrap(); }
    println!("Counter = {}", counter.lock().unwrap());
}

fn main() {
    let c = Counters::default();
    c.record_hit(); c.record_hit(); c.record_miss();
    println!("Hit ratio: {:.2}", c.ratio());

    let g = Graph { edges: RefCell::new(Vec::new()) };
    g.add_edge(0, 1); g.add_edge(0, 2);
    println!("Degree of 0: {}", g.degree(0));

    concurrent_counter();
}
```

| Primitive | Thread-safe | Overhead | Types |
|-----------|-------------|----------|-------|
| `Cell<T>` | No | Zero | `T: Copy` only |
| `RefCell<T>` | No | Borrow check at runtime | Any `T` |
| `Mutex<T>` | Yes | OS mutex + cache line | Any `T: Send` |
| `RwLock<T>` | Yes | OS + reader tracking | Multiple readers OR one writer |

