use std::net::SocketAddr;

// Each state is a distinct type — impossible to call the wrong method
struct Closed;
struct Listening { port: u16 }
struct Established { peer: SocketAddr, local_port: u16 }
struct CloseWait { peer: SocketAddr }

struct TcpConn<S> {
    state: S,
}

// Transitions from Closed
impl TcpConn<Closed> {
    pub fn new() -> Self {
        TcpConn { state: Closed }
    }

    pub fn listen(self, port: u16) -> TcpConn<Listening> {
        println!("Binding to port {port}");
        TcpConn { state: Listening { port } }
    }

    pub fn connect(self, peer: SocketAddr, local_port: u16) -> TcpConn<Established> {
        println!("Connecting to {peer}");
        TcpConn { state: Established { peer, local_port } }
    }
}

// Transitions from Listening
impl TcpConn<Listening> {
    pub fn accept(self, peer: SocketAddr) -> TcpConn<Established> {
        println!("Accepted connection from {peer} on port {}", self.state.port);
        TcpConn { state: Established { peer, local_port: self.state.port } }
    }

    pub fn close(self) -> TcpConn<Closed> {
        println!("Stopped listening on port {}", self.state.port);
        TcpConn { state: Closed }
    }
}

// Operations available only in Established state
impl TcpConn<Established> {
    pub fn send(&self, data: &[u8]) {
        println!("Sending {} bytes to {}", data.len(), self.state.peer);
    }

    pub fn recv(&self) -> Vec<u8> {
        println!("Receiving from {}", self.state.peer);
        vec![1, 2, 3] // Simulated
    }

    pub fn close(self) -> TcpConn<CloseWait> {
        println!("Initiating close with {}", self.state.peer);
        TcpConn { state: CloseWait { peer: self.state.peer } }
    }
}

impl TcpConn<CloseWait> {
    pub fn finish_close(self) -> TcpConn<Closed> {
        println!("Connection with {} fully closed", self.state.peer);
        TcpConn { state: Closed }
    }
}

fn main() {
    let peer: SocketAddr = "127.0.0.1:12345".parse().unwrap();

    // Server path
    let closed = TcpConn::new();
    let listening = closed.listen(8080);
    let established = listening.accept(peer);
    established.send(b"HTTP/1.1 200 OK");
    let _ = established.recv(); // moved, can't use `established` again
    // established.send(b"again");  // compile error: value used after move

    // The above line moves `established` — replaced by close_wait
    // We'd need to reorganize if we wanted to send then close:
    let conn = TcpConn::new().listen(9090).accept(peer);
    conn.send(b"hello");
    let close_wait = conn.close();
    let _final = close_wait.finish_close();

    // Can't call send() on CloseWait — it doesn't have that method
    // close_wait.send(b"too late");  // compile error
}
```

**Typestate advantage over runtime checks:** The illegal transitions (e.g., `send()` on a closed socket) are caught by the compiler as "method not found" rather than panics at runtime.

