use tokio::time::{Duration, sleep};
use rand::Rng;

#[derive(Debug)]
struct RetryConfig {
    max_attempts: u32,
    base_delay: Duration,
    max_delay: Duration,
    jitter: bool,
}

impl Default for RetryConfig {
    fn default() -> Self {
        RetryConfig {
            max_attempts: 5,
            base_delay: Duration::from_millis(100),
            max_delay: Duration::from_secs(30),
            jitter: true,
        }
    }
}

#[derive(Debug)]
enum RetryError<E> {
    MaxAttemptsExceeded { attempts: u32, last_error: E },
}

impl<E: std::fmt::Display> std::fmt::Display for RetryError<E> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            RetryError::MaxAttemptsExceeded { attempts, last_error } => {
                write!(f, "Failed after {attempts} attempts: {last_error}")
            }
        }
    }
}

async fn with_retry<F, Fut, T, E>(
    config: &RetryConfig,
    mut operation: F,
) -> Result<T, RetryError<E>>
where
    F: FnMut() -> Fut,
    Fut: std::future::Future<Output = Result<T, E>>,
    E: std::fmt::Debug,
{
    let mut rng = rand::thread_rng();
    let mut last_error = None;

    for attempt in 0..config.max_attempts {
        match operation().await {
            Ok(value) => {
                if attempt > 0 {
                    println!("Succeeded on attempt {}", attempt + 1);
                }
                return Ok(value);
            }
            Err(e) => {
                eprintln!("Attempt {} failed: {e:?}", attempt + 1);
                last_error = Some(e);

                if attempt + 1 < config.max_attempts {
                    // Exponential backoff: base * 2^attempt
                    let exp_delay = config.base_delay
                        .saturating_mul(1u32 << attempt.min(20));
                    let delay = exp_delay.min(config.max_delay);

                    let final_delay = if config.jitter {
                        // Full jitter: uniform [0, delay)
                        let millis = rng.gen_range(0..=delay.as_millis() as u64);
                        Duration::from_millis(millis)
                    } else {
                        delay
                    };

                    println!("Retrying in {:?}...", final_delay);
                    sleep(final_delay).await;
                }
            }
        }
    }

    Err(RetryError::MaxAttemptsExceeded {
        attempts: config.max_attempts,
        last_error: last_error.unwrap(),
    })
}

// Example fallible operation
async fn flaky_call(attempt_counter: &std::sync::atomic::AtomicU32) -> Result<String, String> {
    let n = attempt_counter.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
    if n < 3 {
        Err(format!("Transient error on attempt {}", n + 1))
    } else {
        Ok(format!("Success on attempt {}", n + 1))
    }
}

#[tokio::main]
async fn main() {
    let counter = std::sync::atomic::AtomicU32::new(0);
    let config = RetryConfig {
        max_attempts: 5,
        base_delay: Duration::from_millis(50),
        max_delay: Duration::from_secs(2),
        jitter: false, // deterministic for demo
    };

    match with_retry(&config, || flaky_call(&counter)).await {
        Ok(msg) => println!("Result: {msg}"),
        Err(e) => eprintln!("Final error: {e}"),
    }
}
```

**Jitter rationale:** Without jitter, all clients retry at the same times, creating thundering herd spikes. Full jitter spreads retries uniformly, reducing peak server load by ~50%.

