use std::ptr::NonNull;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::cell::Cell;

/// An intrusive node — embed this directly in the data structure.
/// The list does not own the node; the node is part of the element itself.
pub struct IntrusiveNode {
    prev: Cell<Option<NonNull<IntrusiveNode>>>,
    next: Cell<Option<NonNull<IntrusiveNode>>>,
}

impl IntrusiveNode {
    pub const fn new() -> Self {
        IntrusiveNode {
            prev: Cell::new(None),
            next: Cell::new(None),
        }
    }
}

/// Intrusive doubly-linked list.
/// Elements are not owned by the list — they must outlive it.
pub struct IntrusiveList {
    head: Option<NonNull<IntrusiveNode>>,
    tail: Option<NonNull<IntrusiveNode>>,
    len: usize,
}

impl IntrusiveList {
    pub fn new() -> Self {
        IntrusiveList { head: None, tail: None, len: 0 }
    }

    /// Insert a node at the front.
    /// SAFETY: `node` must remain valid (not moved or dropped) as long as it's in the list.
    pub unsafe fn push_front(&mut self, node: &IntrusiveNode) {
        let node_ptr = NonNull::from(node);
        node.prev.set(None);
        node.next.set(self.head);

        if let Some(old_head) = self.head {
            old_head.as_ref().prev.set(Some(node_ptr));
        } else {
            self.tail = Some(node_ptr);
        }
        self.head = Some(node_ptr);
        self.len += 1;
    }

    /// Remove a specific node from the list.
    /// SAFETY: node must currently be in this list.
    pub unsafe fn remove(&mut self, node: &IntrusiveNode) {
        let prev = node.prev.get();
        let next = node.next.get();

        if let Some(p) = prev {
            p.as_ref().next.set(next);
        } else {
            self.head = next;
        }

        if let Some(n) = next {
            n.as_ref().prev.set(prev);
        } else {
            self.tail = prev;
        }

        node.prev.set(None);
        node.next.set(None);
        self.len -= 1;
    }

    pub fn len(&self) -> usize { self.len }

    pub fn is_empty(&self) -> bool { self.len == 0 }
}

// --- Demo: a Task struct with an embedded intrusive node ---
struct Task {
    id: u64,
    node: IntrusiveNode, // embedded — no separate allocation
}

impl Task {
    fn new(id: u64) -> Self {
        Task { id, node: IntrusiveNode::new() }
    }
}

fn main() {
    let mut list = IntrusiveList::new();

    let t1 = Task::new(1);
    let t2 = Task::new(2);
    let t3 = Task::new(3);

    // SAFETY: t1, t2, t3 are pinned to this stack frame and outlive `list`.
    // In production code, use Pin<Box<Task>> to guarantee stability.
    unsafe {
        list.push_front(&t1.node);
        list.push_front(&t2.node);
        list.push_front(&t3.node);

        println!("List len: {}", list.len()); // 3

        list.remove(&t2.node);
        println!("After remove: {}", list.len()); // 2
    }
}
```

**Intrusive lists vs standard collections:**
- Zero extra allocations — the node is embedded in the element.
- O(1) removal given a pointer to the node.
- Used in OS kernels, async runtimes (Tokio's task queues), and real-time systems.
- Requires `unsafe` because Rust can't verify the lifetime relationship between nodes and the list.

```rust
use tokio::net::{TcpListener, TcpStream};
use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
use serde::{Deserialize, Serialize};

#[derive(Debug, Deserialize)]
#[serde(tag = "method", content = "params")]
enum RpcRequest {
    Echo { message: String },
    Add { a: f64, b: f64 },
    Reverse { text: String },
}

#[derive(Debug, Serialize)]
#[serde(untagged)]
enum RpcResponse {
    Ok { result: serde_json::Value },
    Err { error: String },
}

async fn dispatch(request: RpcRequest) -> RpcResponse {
    match request {
        RpcRequest::Echo { message } => RpcResponse::Ok {
            result: serde_json::Value::String(message),
        },
        RpcRequest::Add { a, b } => RpcResponse::Ok {
            result: serde_json::json!(a + b),
        },
        RpcRequest::Reverse { text } => RpcResponse::Ok {
            result: serde_json::Value::String(text.chars().rev().collect()),
        },
    }
}

async fn handle_client(stream: TcpStream, addr: std::net::SocketAddr) {
    println!("Client connected: {addr}");
    let (reader, mut writer) = stream.into_split();
    let mut lines = BufReader::new(reader).lines();

    while let Ok(Some(line)) = lines.next_line().await {
        let response = match serde_json::from_str::<RpcRequest>(&line) {
            Ok(req) => dispatch(req).await,
            Err(e) => RpcResponse::Err {
                error: format!("parse error: {e}"),
            },
        };

        let mut json = serde_json::to_string(&response).unwrap();
        json.push('\n');
        if writer.write_all(json.as_bytes()).await.is_err() {
            break;
        }
    }
    println!("Client disconnected: {addr}");
}

#[tokio::main]
async fn main() -> std::io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:7878").await?;
    println!("JSON-RPC server on port 7878");
    println!("Protocol: one JSON object per line");
    println!('  Example: {{"method":"Add","params":{{"a":3,"b":4}}}}');

    loop {
        let (stream, addr) = listener.accept().await?;
        tokio::spawn(handle_connection(stream, addr));
    }
}

async fn handle_connection(stream: TcpStream, addr: std::net::SocketAddr) {
    handle_client(stream, addr).await;
}
```

**Protocol design:**
- One JSON object per line (`\n`-delimited) — easy to implement in any client language.
- `#[serde(tag = "method", content = "params")]` maps directly to a JSON-RPC-like format.
- `BufReader::lines()` handles partial reads and buffering automatically.
- Each connection is independent — one slow client can't block others.

```rust
use rayon::prelude::*;
use rayon::ThreadPoolBuilder;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

#[derive(Debug, Clone)]
struct Record {
    id: u64,
    value: f64,
    tags: Vec<String>,
}

#[derive(Debug)]
struct ProcessedRecord {
    id: u64,
    normalized: f64,
    tag_count: usize,
    checksum: u64,
}

fn process_record(rec: &Record, global_max: f64) -> ProcessedRecord {
    // Simulate CPU-bound work
    let normalized = rec.value / global_max;
    let checksum = rec.tags.iter()
        .map(|t| t.bytes().map(|b| b as u64).sum::<u64>())
        .sum::<u64>() ^ rec.id;

    ProcessedRecord {
        id: rec.id,
        normalized,
        tag_count: rec.tags.len(),
        checksum,
    }
}

fn main() {
    // Custom thread pool: 4 threads, named for profiling visibility
    let pool = ThreadPoolBuilder::new()
        .num_threads(4)
        .thread_name(|i| format!("worker-{i}"))
        .build()
        .unwrap();

    let records: Vec<Record> = (0..10_000)
        .map(|i| Record {
            id: i,
            value: (i as f64 * 1.7).sin().abs() * 1000.0,
            tags: vec![format!("tag-{}", i % 10), format!("cat-{}", i % 5)],
        })
        .collect();

    pool.install(|| {
        // Parallel reduce to find global max (two-pass normalization)
        let global_max: f64 = records.par_iter()
            .map(|r| r.value)
            .reduce(|| 0.0_f64, f64::max);

        println!("Global max: {global_max:.4}");

        // Parallel map-filter-collect
        let processed: Vec<ProcessedRecord> = records.par_iter()
            .map(|r| process_record(r, global_max))
            .filter(|p| p.normalized > 0.5)
            .collect();

        println!("Processed {} records above threshold", processed.len());

        // Parallel fold with local accumulators, then reduce
        let total_checksum: u64 = processed.par_iter()
            .map(|p| p.checksum)
            .reduce(|| 0, |a, b| a.wrapping_add(b));

        println!("Total checksum: {total_checksum:#018X}");

        // Parallel sort (in-place)
        let mut sorted = processed;
        sorted.par_sort_unstable_by(|a, b| {
            b.normalized.partial_cmp(&a.normalized).unwrap()
        });
        println!("Top record: {:?}", sorted.first().unwrap());
    });
}
```

**Rayon patterns:**
- `par_iter()` — parallel iterator over a slice.
- `reduce(identity, fold_fn)` — parallel fold with a commutative + associative operation.
- `pool.install(|| ...)` — run work on a specific thread pool, useful for isolating libraries.
- `par_sort_unstable_by` — parallel quicksort, ~2x faster than sequential on large data.
- Rayon automatically load-balances using work stealing — no manual thread management.
